// Using Monitor
private readonly object lockObj = new object();
private bool isPaused = false;

void DoWork()
{
    while (true)
    {
        lock (lockObj)
        {
            while (isPaused)
            {
                Monitor.Wait(lockObj); // Compliant
            }
        }
        // Do actual work
    }
}

void Pause() { lock (lockObj) { isPaused = true; } }
void Resume() { lock (lockObj) { isPaused = false; Monitor.PulseAll(lockObj); } }

// Using ManualResetEvent
private ManualResetEvent pauseEvent = new ManualResetEvent(true);

void DoWork()
{
    while (true)
    {
        pauseEvent.WaitOne(); // Compliant - blocks when reset
        // Do actual work
    }
}

void Pause() { pauseEvent.Reset(); }
void Resume() { pauseEvent.Set(); }
